  if ( mode == 2 ) {
    return sampleProbeBlendLocalDiffuse(
      probeLocalPosition,
      probeLocalDirection,
      probeBlendWeights,
      intensity
    );
  }

  if ( mode == 3 ) {
    return vec3( 0.0 );
  }

  return vec3( 0.0 );
